// Queue for BFS
typedef struct {
    TreeNode** data;
    int front, rear, size;
} Queue;

Queue* createQueue(int size) {
    Queue* q = (Queue*)malloc(sizeof(Queue));
    q->data = (TreeNode**)malloc(sizeof(TreeNode*) * size);
    q->front = q->rear = 0;
    q->size = size;
    return q;
}

void push(Queue* q, TreeNode* node) {
    q->data[q->rear++] = node;
}

TreeNode* pop(Queue* q) {
    return q->data[q->front++];
}

int isEmpty(Queue* q) {
    return q->front == q->rear;
}

// Deserialize from level-order array (-1 means null)
TreeNode* deserialize(int* arr, int n) {
    if (n == 0 || arr[0] == -1) return NULL;

    TreeNode* root = newNode(arr[0]);
    Queue* q = createQueue(n);
    push(q, root);

    int i = 1;
    while (!isEmpty(q) && i < n) {
        TreeNode* node = pop(q);

        // Left child
        if (i < n && arr[i] != -1) {
            node->left = newNode(arr[i]);
            push(q, node->left);
        }
        i++;

        // Right child
        if (i < n && arr[i] != -1) {
            node->right = newNode(arr[i]);
            push(q, node->right);
        }
        i++;
    }

    return root;
}

// Serialize tree using BFS, fill -1 for nulls
int* serialize(TreeNode* root, int* outSize) {
    if (!root) {
        *outSize = 0;
        return NULL;
    }

    int cap = 20000; // maximum possible size
    int* result = (int*)malloc(sizeof(int) * cap);
    int idx = 0;

    Queue* q = createQueue(cap);
    push(q, root);

    while (!isEmpty(q)) {
        TreeNode* node = pop(q);

        if (node) {
            result[idx++] = node->val;
            push(q, node->left);
            push(q, node->right);
        } else {
            result[idx++] = -1;
        }
    }

    // Remove trailing -1 values
    while (idx > 0 && result[idx - 1] == -1) {
        idx--;
    }

    *outSize = idx;
    return result;
}

