static List<Integer> serialize(TreeNode root) {
    List<Integer> res = new ArrayList<>();
    if (root == null) return res;

    Queue<TreeNode> q = new LinkedList<>();
    q.offer(root);

    while (!q.isEmpty()) {
        TreeNode node = q.poll();
        if (node != null) {
            res.add(node.val);
            q.offer(node.left);
            q.offer(node.right);
        } else {
            res.add(-1);
        }
    }

    // Remove trailing -1s
    while (!res.isEmpty() && res.get(res.size() - 1) == -1) {
        res.remove(res.size() - 1);
    }

    return res;
}

